"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { useAdminHeader } from "../components/AdminHeaderContext";
import { apiFetch, apiUrl, ApiError } from "@/lib/api";
import { glassStyle, type Actor } from "./shared";

export default function ActorList() {
  useAdminHeader("Actors", "Manage actor profiles used across your movie cast lists.");

  const [actors, setActors] = useState<Actor[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [search, setSearch] = useState("");

  useEffect(() => {
    apiFetch<Actor[]>("/actors", { auth: false })
      .then(setActors)
      .catch((err) => setError(err instanceof ApiError ? err.message : "Failed to load actors"))
      .finally(() => setLoading(false));
  }, []);

  const handleDelete = async (id: number) => {
    if (!confirm("Delete this actor? This can't be undone.")) return;
    const previous = actors;
    setActors((prev) => prev.filter((a) => a.actor_id !== id));
    try {
      await apiFetch(`/actors/${id}`, { method: "DELETE" });
    } catch (err) {
      setActors(previous);
      setError(err instanceof ApiError ? err.message : "Failed to delete actor");
    }
  };

  const filtered = actors.filter((a) => search === "" || a.name.toLowerCase().includes(search.toLowerCase()));

  return (
    <main className="px-5 md:px-20 pb-24 md:pb-8 max-w-[1600px] mx-auto w-full">
      <div className="flex flex-col md:flex-row justify-end items-start md:items-center gap-4 mb-8">
        <div className="flex items-center gap-2 w-full md:w-auto">
          <div className="relative flex-1 md:w-64">
            <span className="material-symbols-outlined absolute left-3 top-1/2 -translate-y-1/2" style={{ fontSize: 20, color: "#e9bcb6" }}>search</span>
            <input
              type="text"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search actors..."
              className="w-full rounded-lg pl-10 pr-4 py-2 text-base text-white transition-colors outline-none"
              style={{ background: "#201f1f", border: "1px solid #5e3f3b", caretColor: "#ffb4aa" }}
            />
          </div>
          <Link
            href="/admin/actors/new"
            className="flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold text-white transition-all hover-scale"
            style={{ background: "#e50914", boxShadow: "0 0 15px rgba(229,9,20,0.30)" }}
          >
            <span className="material-symbols-outlined" style={{ fontSize: 18 }}>person_add</span>
            <span className="hidden sm:inline">Add Actor</span>
          </Link>
        </div>
      </div>

      {error && <p className="mb-4 text-sm" style={{ color: "#ff8a80" }}>{error}</p>}
      {loading && <p className="text-sm" style={{ color: "#e9bcb6" }}>Loading actors...</p>}
      {!loading && filtered.length === 0 && <p className="text-sm" style={{ color: "#e9bcb6" }}>No actors found.</p>}

      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-5">
        {filtered.map((a) => {
          const photo = apiUrl(a.photo_url);
          return (
            <div key={a.actor_id} className="rounded-xl overflow-hidden hover-lift flex flex-col items-center p-4 gap-2" style={glassStyle()}>
              <div className="rounded-full overflow-hidden flex items-center justify-center" style={{ width: 80, height: 80, background: "#151414", border: "1px solid #5e3f3b" }}>
                {photo ? (
                  <img src={photo} alt={a.name} className="w-full h-full object-cover" />
                ) : (
                  <span className="material-symbols-outlined" style={{ color: "#5e3f3b", fontSize: 32 }}>person</span>
                )}
              </div>
              <h3 className="text-sm font-semibold text-white text-center truncate w-full">{a.name}</h3>
              <div className="flex gap-2 mt-1">
                <Link
                  href={`/admin/actors/${a.actor_id}/edit`}
                  className="w-8 h-8 rounded-full flex items-center justify-center transition-colors"
                  style={{ background: "rgba(255,255,255,0.08)", color: "#e9bcb6" }}
                  title="Edit actor"
                >
                  <span className="material-symbols-outlined" style={{ fontSize: 16 }}>edit</span>
                </Link>
                <button
                  onClick={() => handleDelete(a.actor_id)}
                  className="w-8 h-8 rounded-full flex items-center justify-center transition-colors"
                  style={{ background: "rgba(255,255,255,0.08)", color: "#ff8a80" }}
                  title="Delete actor"
                >
                  <span className="material-symbols-outlined" style={{ fontSize: 16 }}>delete</span>
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </main>
  );
}
